INSERT INTO tools (name, name_en, category, description, description_en, price, rating, official_url, features, is_recommended, is_hot, is_new, slug, short_tag, full_desc, highlights, drawbacks, tg_advice, tags, sort_order, status) VALUES
('Consensus', 'Consensus', '学生', 'AI学术搜索引擎，专门检索同行评审论文，自动提取研究结论和共识，2026年新增AI论文综述自动生成功能。', 'AI academic search engine for peer-reviewed papers with auto-extracted conclusions and consensus.', '免费+$9/月', 4.8, 'https://consensus.app', ARRAY['同行评审论文检索','研究共识提取','AI综述自动生成','研究结论对比'], true, true, true, 'consensus', 'AI学术共识', 'Consensus，快速找到学术研究共识的AI工具', ARRAY['专注同行评审质量高','共识提取准确','综述生成功能新'], ARRAY['主要英文文献','数据库不如Google Scholar全'], '需要快速了解某领域研究共识的学者', ARRAY['热门','TG精选','2026新品'], 4800, 'active');
