('秘塔AI搜索', '秘塔AI搜索', '学生', '国内领先的AI搜索引擎，无广告干扰，中文学术内容理解能力强，支持深度搜索模式，完全免费使用。', 'Leading Chinese AI search engine, ad-free with strong Chinese academic content understanding, free.', '免费', 4.7, 'https://metaso.cn', ARRAY['无广告AI搜索','中文学术内容优化','深度搜索模式','来源引用展示'], true, true, false, 'metaso', 'AI中文搜索', '秘塔AI搜索，国内最好用的免费AI搜索', ARRAY['完全免费无广告','中文理解最强','深度搜索质量高'], ARRAY['英文内容不如Perplexity','实时性稍弱'], '国内学生和研究者免费AI搜索首选', ARRAY['热门','国产精品','免费'], 4700, 'active');
INSERT INTO tools (name, name_en, category, description, description_en, price, rating, official_url, features, is_recommended, is_hot, is_new, slug, short_tag, full_desc, highlights, drawbacks, tg_advice, tags, sort_order, status) VALUES
